inline const float UCT1C = std::sqrt(2);

inline i16 spla(const i16 i, const i16 j){ // maps position to a number
    return i * DIM + j;
}
inline i16 spla(const Pos x){
    return spla(x.i, x.j);
}
inline Pos rozs(const i16 i){ // maps number to a position
    return rozs_lookup[i];
}
inline bool inbs(const i16 a, const i16 x, const i16 b){ // is x >= a and x < b
    return a <= x && x < b;
}
inline bool inbs(const i16 a, const Pos x, const i16 b){ // is x >= a and x < b
    return inbs(a, x.i, b) && inbs(a, x.j, b);
}

struct BitBoard: public std::bitset<BRDSZ>{
    using std::bitset<BRDSZ>::bitset;
    bool g(const i16 i, const i16 j) const;
    bool g(const Pos& pos) const;
    void s(const i16 i, const i16 j, const bool v);
    void s(const Pos& pos, const bool v);
    void clear();
    void find_ones(PosList& l);
};

struct Zobrist{
    u64 z[2];
    Zobrist();

    bool operator==(const Zobrist& other) const;
    u64& operator[](const int i);
    const u64& operator[](const int i) const;
};

struct HistoryEntry{
    std::array<BitBoard, 2> brd;
    Zobrist hash;
    i16 passes;
};

struct History: public std::vector<HistoryEntry>{
    using std::vector<HistoryEntry>::vector;
    void add(const HistoryEntry& m);
    void pop();
};


